+    fn build_epoch_records(
+        epoch_id: u64,
+        seed: u64,
+        k_source: u16,
+        r_repair: u16,
+    ) -> (u64, Vec<EvidenceSymbolRecord>) {
+        let family = ApiFamily::Allocator;
+        let mode = SafetyLevel::Hardened;
+        let action = MembraneAction::Allow;
+        let profile = ValidationProfile::Fast;
