+            truncate(&epoch_hex, w_epoch),
+            truncate(&seed_hex, w_seed),
+            truncate(&fm, w_fm),
+            truncate(&kr, w_kr),
+            truncate(&recs, w_recs),
+            truncate(&hash, w_hash),
+            truncate(&dec, w_dec),
