+}
+
+fn truncate(s: &str, width: usize) -> String {
+    if s.len() <= width {
+        return s.to_string();
+    }
+    if width <= 3 {
+        return s[..width].to_string();
+    }
+    format!("{}...", &s[..(width - 3)])
+}
